mapper.select:
SELECT si.job_id, sn.BUSINESS_KEY, sn.CONTENT, sn.CREATOR, sn.CREATE_TIME FROM spc_note sn JOIN spc_alarm_event sar ON sn.BUSINESS_KEY = sar.ID JOIN spc_indicator si ON si.id = sar.INDICATOR_ID WHERE 1=1
and si.FAC_CODE = #{facCode}
and si.job_id IN
#{jobId}
AND sn.CREATE_TIME = ( SELECT MAX(sn2.CREATE_TIME) FROM spc_note sn2 JOIN spc_alarm_event sar2 ON sn2.BUSINESS_KEY = sar2.ID JOIN spc_indicator si2 ON si2.id = sar2.INDICATOR_ID WHERE si2.job_id = si.job_id )

SELECT sar.id as analysis_id, sn.id as spc_note_id, sar.job_id as job_id , sar.oos as oos, sar.ooc as ooc, sar.oow as oow, sar.oo3 as oo3, sar.normal as normal, sar.segment_id as alarmSegmentId, sar.start_time as alarmStartTime, SAR.end_time as alarmEndTime, sar.peek_value AS point_value, sar.peek_value_time as event_time, sn.content as content, sn.update_time as spc_note_upadte_time, sn.tag as tag, sn.update_time as spc_note_upadte_time FROM spc_alarm_event sar RIGHT JOIN spc_note sn ON sar.id = sn.business_key WHERE sn.indicator_id is not null
and sar.FAC_CODE = #{facCode}
and sar.peek_value_time >= #{startTime}
and sar.peek_value_time <= #{endTime}
and sar.job_id = #{jobId}
and sar.id = #{spcAnalysisResultId}
and sn.tag = #{tag}
ORDER BY sar.id DESC
